sql:
SELECT name
FROM grantees
WHERE founded_year > 2000;

SELECT program_name
FROM grant_programs
WHERE program_type = 'One-Time';

SELECT DISTINCT g.name
FROM grantees g
INNER JOIN grants gr ON g.grantee_id = gr.grantee_id;

SELECT name
FROM grantees
WHERE grantee_id = 0;

SELECT program_name, budget
FROM grant_programs
ORDER BY budget DESC;

SELECT grant_id
FROM grant_payments
WHERE payment_status != 'Completed';

SELECT COUNT(*) AS federal_grant_programs
FROM grant_programs
WHERE funding_source = 'Federal';

SELECT program_name, CAST(REPLACE(budget, ',', '') AS INTEGER) AS total_budget
FROM grant_programs
ORDER BY total_budget DESC;

SELECT program_name, budget
FROM grant_programs
ORDER BY CAST(REPLACE(REPLACE(budget, ',', ''), '$', '') AS INTEGER) DESC;

SELECT name
FROM grantees
WHERE grantee_id IN (
  SELECT grantee_id
  FROM grant_applications
);
